<template>
  <div>
    <HeroHeaderDashboard :title="title" :breadcrumbs="breadcrumbs" />
    <BoxContent>
      <template #content>
        <BoxInformation title="Información" :columns="2">
          <CardInfoDashboard
            v-if="item"
            title="ID"
            :description="String(item.id)"
          />
          <CardInfoDashboard
            v-if="item"
            title="Usuario"
            :description="item.user?.username || '--'"
          />
          <CardInfoDashboard
            v-if="item"
            title="Anuncio"
            :description="item.ad?.name || '--'"
          />
          <CardInfoDashboard
            v-if="item"
            title="Precio"
            :description="formatCurrency(item.price)"
          />
          <CardInfoDashboard
            v-if="item"
            title="Días"
            :description="formatDays(item.total_days)"
          />
          <CardInfoDashboard
            v-if="item"
            title="Descripción"
            :description="item.description || '--'"
          />
        </BoxInformation>
      </template>
      <template #sidebar>
        <BoxInformation title="Detalles" :columns="1">
          <CardInfoDashboard
            v-if="item"
            title="Fecha de creación"
            :description="formatDate(item.createdAt)"
          />
          <CardInfoDashboard
            v-if="item"
            title="Última modificación"
            :description="formatDate(item.updatedAt)"
          />
        </BoxInformation>
      </template>
    </BoxContent>
  </div>
</template>

<script setup lang="ts">
import { ref, computed } from "vue";
import { useRoute } from "vue-router";
import { formatCurrency } from "@/utils/price";
import { formatDays } from "@/utils/string";
import { formatDate } from "@/utils/date";

interface FeaturedRecord {
  id: number;
  price: number;
  total_days: number;
  description?: string;
  createdAt: string;
  updatedAt: string;
  user?: { username: string };
  ad?: { name: string } | null;
}

definePageMeta({
  layout: "dashboard",
});

const route = useRoute();
const item = ref<FeaturedRecord | null>(null);
const apiClient = useApiClient();

const title = computed(() =>
  item.value?.id ? `Destacado #${item.value.id}` : "Destacado",
);
const breadcrumbs = computed(() => [
  { label: "Destacados", to: "/dashboard/featured/free" },
  ...(item.value?.id ? [{ label: `#${item.value.id}` }] : []),
]);

const { data: featuredData } = await useAsyncData(
  `featured-${route.params.id}`,
  async () => {
    const id = route.params.id;
    if (!id) return null;
    try {
      const response = (await apiClient("ad-featured-reservations", {
        method: "GET",
        params: {
          filters: { id: { $eq: id } },
          populate: {
            user: { fields: ["username"] },
            ad: { fields: ["name"] },
          },
        } as unknown as Record<string, unknown>,
      })) as { data: unknown[] };
      const data = Array.isArray(response.data) ? response.data[0] : null;
      if (data) return data;

      const fallback = (await apiClient(`ad-featured-reservations/${id}`, {
        method: "GET",
        params: {
          populate: {
            user: { fields: ["username"] },
            ad: { fields: ["name"] },
          },
        } as unknown as Record<string, unknown>,
      })) as { data: unknown };
      return (fallback.data as unknown) || null;
    } catch (error) {
      console.error("Error fetching featured reservation:", error);
      return null;
    }
  },
);

item.value = (featuredData.value as FeaturedRecord | null) ?? null;
</script>
